import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Router } from '@angular/router';
import { AlumnoDashboardService, AlumnoCurso } from '../../../core/services/alumno-dashboard.service';
import { FormsModule } from '@angular/forms';
import { matchesQuery, paginate, sortByDate, totalPages, SortOrder } from '../../../core/utils/listing.utils';

@Component({
  selector: 'app-mis-cursos',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  templateUrl: './mis-cursos.component.html',
  styleUrls: ['./mis-cursos.component.css']
})
export class MisCursosComponent implements OnInit {
  private studentService = inject(AlumnoDashboardService);
  private router = inject(Router);

  cursos: AlumnoCurso[] = [];
  isLoading = true;
  searchTerm = '';
  dateSortOrder: SortOrder = 'desc';
  currentPage = 1;
  pageSize = 6;

  ngOnInit(): void {
    this.studentService.getEnrolledCursos().subscribe({
      next: (data) => {
        this.cursos = data;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error fetching enrolled courses:', err);
        this.isLoading = false;
      }
    });
  }

  get filteredCursos(): AlumnoCurso[] {
    const matches = this.cursos.filter(curso =>
      matchesQuery([
        curso.nombre,
        curso.descripcion,
        curso.nivelSuscripcion,
        curso.fechaMatricula
      ], this.searchTerm)
    );
    return sortByDate(matches, curso => curso.fechaMatricula, this.dateSortOrder);
  }

  get totalPages(): number {
    return totalPages(this.filteredCursos.length, this.pageSize);
  }

  get pagedCursos(): AlumnoCurso[] {
    return paginate(this.filteredCursos, this.currentPage, this.pageSize);
  }

  onSearchChange(): void {
    this.currentPage = 1;
  }

  toggleDateSort(): void {
    this.dateSortOrder = this.dateSortOrder === 'desc' ? 'asc' : 'desc';
    this.currentPage = 1;
  }

  previousPage(): void {
    if (this.currentPage > 1) this.currentPage--;
  }

  nextPage(): void {
    if (this.currentPage < this.totalPages) this.currentPage++;
  }

  continueCourse(courseId: number): void {
    this.router.navigate(['/dashboard/cursos-play', courseId]);
  }
}
<div class="space-y-8 font-body text-slate-800 dark:text-slate-200 transition-colors duration-300">
  <div class="border border-slate-200 dark:border-slate-800 p-8 bg-white dark:bg-slate-900 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col md:flex-row md:items-center md:justify-between gap-4">
    <div>
      <h1 class="text-2xl font-black text-slate-900 dark:text-slate-100 tracking-tight uppercase leading-none">Mis Cursos</h1>
      <p class="text-slate-500 dark:text-slate-400 text-xs mt-2">Explora tus cursos activos, filtra por texto y ordena por fecha de matrícula.</p>
    </div>
    <div class="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
      <label class="flex items-center gap-2 border border-slate-200 dark:border-slate-700 px-3 py-2 bg-slate-50 dark:bg-slate-800 w-full sm:w-72">
        <span class="material-symbols-outlined text-sm text-slate-400">search</span>
        <input [(ngModel)]="searchTerm" (ngModelChange)="onSearchChange()" type="text" placeholder="Buscar curso, plan o fecha" class="w-full bg-transparent outline-none text-sm text-slate-900 dark:text-slate-100 placeholder:text-slate-400">
      </label>
      <button (click)="toggleDateSort()" class="px-4 py-2 border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
        <span class="material-symbols-outlined text-sm">schedule</span>
        <span>Fecha {{ dateSortOrder === 'desc' ? '↓' : '↑' }}</span>
      </button>
    </div>
  </div>

  <div *ngIf="isLoading" class="flex flex-col items-center justify-center p-20 border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
    <span class="animate-spin inline-block w-8 h-8 border-4 border-primary border-t-transparent rounded-full mb-3"></span>
    <span class="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Cargando tus cursos...</span>
  </div>

  <div *ngIf="!isLoading && filteredCursos.length === 0" class="border border-slate-200 dark:border-slate-800 p-12 text-center bg-white dark:bg-slate-900">
    <span class="material-symbols-outlined text-5xl text-slate-300 dark:text-slate-600 mb-2">auto_stories</span>
    <h3 class="text-sm font-bold text-slate-800 dark:text-slate-100 uppercase">Sin resultados</h3>
    <p class="text-slate-500 dark:text-slate-400 text-xs mt-1.5 max-w-sm mx-auto">No encontramos cursos con esos criterios.</p>
  </div>

  <div *ngIf="!isLoading && pagedCursos.length > 0" class="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
    <div *ngFor="let curso of pagedCursos" class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 flex flex-col justify-between overflow-hidden shadow-[4px_4px_0px_0px_rgba(15,23,42,0.04)]">
      <div>
        <div class="relative h-44 bg-slate-100 dark:bg-slate-800 border-b border-slate-200 dark:border-slate-800 overflow-hidden">
          <img [src]="curso.imagenPortada || 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3'" class="w-full h-full object-cover" alt="Portada Curso">
          <span class="absolute top-3 right-3 text-[9px] font-black uppercase tracking-widest border px-2 py-0.5 bg-white/90 dark:bg-slate-900/90">{{ curso.nivelSuscripcion }}</span>
        </div>
        <div class="p-6">
          <div class="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-2">
            <span class="material-symbols-outlined text-xs">event</span>
            <span>{{ curso.fechaMatricula | date:'dd/MM/yyyy HH:mm' }}</span>
          </div>
          <h2 class="text-sm font-black text-slate-900 dark:text-slate-100 uppercase tracking-tight leading-snug line-clamp-1">{{ curso.nombre }}</h2>
          <p class="text-slate-500 dark:text-slate-400 text-xs mt-2 line-clamp-3 leading-relaxed">{{ curso.descripcion }}</p>
        </div>
      </div>
      <div class="p-6 pt-0 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
        <div class="mt-4">
          <div class="flex justify-between items-center text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1.5">
            <span>Progreso</span>
            <span class="font-mono text-slate-900 dark:text-slate-100">{{ curso.avancePorcentaje }}%</span>
          </div>
          <div class="w-full bg-slate-200 dark:bg-slate-800 h-2 border border-slate-300 dark:border-slate-700 overflow-hidden">
            <div class="bg-slate-900 dark:bg-slate-100 h-full" [style.width.%]="curso.avancePorcentaje"></div>
          </div>
        </div>
        <button (click)="continueCourse(curso.id)" class="mt-6 w-full py-2.5 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest flex items-center justify-center gap-2">
          <span class="material-symbols-outlined text-sm">play_circle</span>
          <span>{{ curso.avancePorcentaje > 0 ? 'Continuar Aprendizaje' : 'Iniciar Curso' }}</span>
        </button>
      </div>
    </div>
  </div>

  <div *ngIf="!isLoading && totalPages > 1" class="flex items-center justify-between border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 px-4 py-3">
    <p class="text-xs font-bold uppercase tracking-widest text-slate-500">Página {{ currentPage }} de {{ totalPages }}</p>
    <div class="flex items-center gap-2">
      <button (click)="previousPage()" [disabled]="currentPage === 1" class="px-3 py-2 border text-xs font-bold uppercase disabled:opacity-40">Anterior</button>
      <button (click)="nextPage()" [disabled]="currentPage === totalPages" class="px-3 py-2 border text-xs font-bold uppercase disabled:opacity-40">Siguiente</button>
    </div>
  </div>
</div>
